// 텍스트에서 의미를 추출하다: 비정형 데이터의 질서화
//
// "let x = 10;" → [Let, Ident("x"), Assign, Int(10), Semicolon, EOF]
// ============================================================================

mod token;
mod lexer;

use lexer::Lexer;
use token::Token;

// ============================================================================
// Section 1: Lexer 기초 - 단순한 프로그램 토큰화
// ============================================================================
fn section_1_basics() {
    println!("\n=== Section 1: Lexer 기초 ===");
    println!("가장 단순한 Gogs-Lang 프로그램을 토큰화:");
    println!();

    let source = "let x = 10;".to_string();
    println!("  입력: {}", source);
    println!("  토큰화 진행:");
    println!();

    let mut lexer = Lexer::new(source);
    let mut token_count = 0;

    loop {
        let token_with_pos = lexer.next_token();
        if token_count < 6 {
            println!("    [{}] {:?}", token_count, token_with_pos.token);
        }
        token_count += 1;
        if token_with_pos.token == Token::EOF {
            break;
        }
    }

    println!();
    println!("  총 {} 개의 토큰 생성", token_count);
    println!("✓ Section 1 완료: 기본 토큰화");
}

// ============================================================================
// Section 2: 연산 표현식 분석
// ============================================================================
fn section_2_arithmetic() {
    println!("\n=== Section 2: 연산 표현식 분석 ===");
    println!("수학 연산식을 토큰으로 분해:");
    println!();

    let source = "x + y * 2 - z / 3".to_string();
    println!("  입력: {}", source);
    println!("  토큰 스트림:");

    let mut lexer = Lexer::new(source);
    let mut idx = 0;

    loop {
        let token_with_pos = lexer.next_token();
        match &token_with_pos.token {
            Token::Ident(name) => {
                print!("  [{}] Ident({})", idx, name);
            }
            Token::Int(n) => {
                print!("  [{}] Int({})", idx, n);
            }
            Token::Plus => print!("  [{}] Plus(+)", idx),
            Token::Minus => print!("  [{}] Minus(-)", idx),
            Token::Asterisk => print!("  [{}] Multiply(*)", idx),
            Token::Slash => print!("  [{}] Divide(/)", idx),
            Token::EOF => {
                println!();
                println!("  [{}] EOF", idx);
                break;
            }
            _ => {}
        }
        if token_with_pos.token != Token::EOF {
            println!();
        }
        idx += 1;
    }

    println!("✓ Section 2 완료: 연산식 분석");
}

// ============================================================================
// Section 3: 키워드 인식
// ============================================================================
fn section_3_keywords() {
    println!("\n=== Section 3: 키워드 인식 ===");
    println!("Gogs-Lang 언어 키워드를 구분:");
    println!();

    let source = "let fn if else return while for true false".to_string();
    println!("  입력: {}", source);
    println!("  토큰 분석:");

    let mut lexer = Lexer::new(source);
    let tokens = lexer.tokenize();

    for (idx, token_with_pos) in tokens.iter().enumerate() {
        if idx >= 8 {
            break; // EOF 제외
        }
        println!("    [{}] {:?}", idx, token_with_pos.token);
    }

    println!("✓ Section 3 완료: 키워드 인식");
}

