            Token::String(s) => println!("    String(\"{}\")", s),
            Token::Int(n) => println!("    Int({})", n),
            Token::Float(f) => println!("    Float({})", f),
            Token::Ident(name) => println!("    Ident({})", name),
            Token::EOF => break,
            _ => {}
        }
    }

    println!("✓ Section 4 완료: 리터럴 분석");
}

