fn section_6_operators() {
    println!("\n=== Section 6: 2글자 연산자 (Peeking) ===");
    println!("Lexer가 peek_char()로 다음 글자를 미리 본 후 올바른 토큰 결정:");
    println!();

    let source = "a == b; c != d; x <= y; z >= 0;".to_string();
