// ============================================================================
fn section_7_positions() {
    println!("\n=== Section 7: 위치 추적 (Line & Column) ===");
    println!("에러 메시지를 위해 각 토큰의 줄과 열 번호 추적:");
    println!();

    let source = "let x = 10;\nlet y = 20;".to_string();
    println!("  입력:");
    println!("    1: let x = 10;");
    println!("    2: let y = 20;");
    println!();
    println!("  각 토큰의 위치:");

    let mut lexer = Lexer::new(source);
    let mut count = 0;

    loop {
        let token_with_pos = lexer.next_token();
        match &token_with_pos.token {
            Token::Let | Token::Ident(_) | Token::Int(_) => {
                println!("    [{}:{}] {:?}",
                    token_with_pos.position.line,
                    token_with_pos.position.column,
                    token_with_pos.token
                );
            }
            Token::EOF => break,
            _ => {}
        }
        count += 1;
        if count > 20 {
            break;
        }
    }

    println!("✓ Section 7 완료: 위치 추적");
}

