fn section_8_complex() {
    println!("\n=== Section 8: 복잡한 프로그램 분석 ===");
    println!("함수 정의를 포함한 복잡한 프로그램 토큰화:");
    println!();

    let source = r#"fn add(x, y) {
    return x + y;
}"#.to_string();

    println!("  입력 프로그램:");
    println!("    fn add(x, y) {{");
    println!("        return x + y;");
    println!("    }}");
    println!();
    println!("  토큰 스트림:");

    let mut lexer = Lexer::new(source);
    let tokens = lexer.tokenize();

    for token_with_pos in tokens.iter() {
        if token_with_pos.token == Token::EOF {
            break;
        }
        println!("    {:?}", token_with_pos.token);
    }

    println!("  총 {} 개 토큰", tokens.len() - 1); // EOF 제외
    println!("✓ Section 8 완료: 복잡한 프로그램");
}

