fn section_9_escape_sequences() {
    println!("\n=== Section 9: 이스케이프 시퀀스 ===");
    println!("문자열 내 이스케이프 시퀀스 처리:");
    println!();

    let source = r#"let greeting = "Hello\nWorld"; let path = "C:\\Users\\alice";"#.to_string();
    println!("  입력:");
    println!("    let greeting = \"Hello\\nWorld\";");
    println!("    let path = \"C:\\\\Users\\\\alice\";");
    println!();
    println!("  해석된 문자열:");

    let mut lexer = Lexer::new(source);
