    println!("✓ Section 9 완료: 이스케이프 시퀀스");
}

// ============================================================================
// Section 10: 토큰 범주 통계
// ============================================================================
fn section_10_statistics() {
    println!("\n=== Section 10: 토큰 범주 통계 ===");
    println!("소스코드의 토큰 분포 분석:");
    println!();

    let source = "let x = 10 + 20; let y = 5 * 2; if x > y { x = y + 1; }".to_string();

    let mut lexer = Lexer::new(source);
    let tokens = lexer.tokenize();

    let mut keywords = 0;
    let mut identifiers = 0;
    let mut numbers = 0;
    let mut operators = 0;
    let mut punctuation = 0;

    for token_with_pos in &tokens {
        match &token_with_pos.token {
            Token::Let | Token::If | Token::Return | Token::While | Token::For => keywords += 1,
            Token::Ident(_) => identifiers += 1,
            Token::Int(_) | Token::Float(_) => numbers += 1,
            Token::Plus | Token::Minus | Token::Asterisk | Token::Slash |
            Token::Assign | Token::EqualEqual | Token::Less | Token::Greater => operators += 1,
            Token::Semicolon | Token::Comma | Token::LeftBrace | Token::RightBrace |
            Token::LeftParen | Token::RightParen => punctuation += 1,
            Token::EOF => {}
            _ => {}
        }
    }

    println!("  소스코드: {}", source);
    println!();
    println!("  토큰 분포:");
    println!("    키워드: {}", keywords);
    println!("    식별자: {}", identifiers);
    println!("    숫자: {}", numbers);
    println!("    연산자: {}", operators);
    println!("    구두점: {}", punctuation);
    println!("    총합: {}", keywords + identifiers + numbers + operators + punctuation);

    println!("✓ Section 10 완료: 통계");
}

