fn section_11_error_handling() {
    println!("\n=== Section 11: 에러 처리 ===");
    println!("정의되지 않은 문자나 닫히지 않은 문자열 감지:");
    println!();

    let sources = vec![
        ("let x = @;", "정의되지 않은 문자 '@'"),
        ("let name = \"unclosed;", "닫히지 않은 문자열"),
    ];

    for (source, description) in sources {
        println!("  경우: {}", description);
        println!("    코드: {}", source);
        println!("    토큰:");

        let mut lexer = Lexer::new(source.to_string());
        loop {
            let token_with_pos = lexer.next_token();
            match &token_with_pos.token {
                Token::Unknown(ch) => {
                    println!("      ⚠️ Unknown('{}')", ch);
                }
                Token::EOF => {
                    println!("      EOF");
                    break;
                }
                token => println!("      {:?}", token),
            }
        }
        println!();
    }

    println!("✓ Section 11 완료: 에러 처리");
}

